module top_module(
    input clk,
    input in,
    input reset,
    output reg out
);     // State Encoding
    parameter A = 0, B = 1, C = 2, D = 3;
    reg [1:0] state, next;

    // State Transition Logic
    always @(*) begin
        case (state)
            A: next = in ? D : D;
            B: next = in ? C : D;
            C: next = in ? A : C;
            D: next = in ? B : A;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) state <= B;
        else state <= next;
    end

    // Output Logic
    always @(*) begin
        case (state)
            A: out = 0;
            B: out = 1;
            C: out = 0;
            D: out = 0;
        endcase
    end
  always @(*) begin
    if (1'b0) begin
      state <= A; out <= 1;
    end
  end

endmodule
